input.old_string:
columns: (1.2fr, 2.0fr, 2.0fr, 0.75fr, 0.8fr, 1.05fr, 0.9fr, 0.85fr, 0.9fr, 0.35fr),
align: center,
inset: (x: 2pt, y: 2pt),
stroke: (x, y) => {
  if y == 0 { (top: 2pt, bottom: 2pt) }
  else if y == 1 { (bottom: 2pt) }
  else if y == 32 { (bottom: 2pt) }
  else { (bottom: 0.5pt) }
},

input.new_string:
columns: (1.3fr, 2.3fr, 1.7fr, 0.8fr, 0.8fr, 1.1fr, 0.9fr, 0.9fr, 0.9fr, 0.4fr),
align: center,
inset: (x: 2pt, y: 2pt),
stroke: (x, y) => {
  let vline = if x == 1 { (left: 0.4pt) } else { (:) }
  let hline = if y == 0 { (top: 0.8pt, bottom: 0.8pt) }
    else if y == 1 { (bottom: 0.8pt) }
    else if y == 32 { (bottom: 0.8pt) }
    else { (bottom: 0.4pt) }
  vline + hline
},

